.about-grid {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 80px;
    align-items: center;
}

.about-image-wrapper {
    position: relative;
}

.about-image-wrapper::before {
    content: '';
    position: absolute;
    top: -20px;
    left: -20px;
    right: 20px;
    bottom: 20px;
    border: 3px solid var(--color-primary);
    border-radius: var(--radius-lg);
    z-index: 0;
}

.about-placeholder {
    background: var(--color-beige);
    border-radius: var(--radius-lg);
    aspect-ratio: 4/5;
    display: flex;
    align-items: center;
    justify-content: center;
    position: relative;
    z-index: 1;
}

.about-placeholder svg {
    width: 80px;
    height: 80px;
    color: var(--color-primary);
    opacity: 0.5;
}

.about-content p {
    color: var(--color-text-light);
    margin-bottom: 20px;
    font-size: 1.0625rem;
}

.stats {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: 30px;
    margin-top: 40px;
    padding-top: 40px;
    border-top: 1px solid var(--color-border);
}

.stat-number {
    display: block;
    font-family: var(--font-display);
    font-size: 2.5rem;
    font-weight: 600;
    color: var(--color-primary);
}

.stat-label {
    font-size: 0.9375rem;
    color: var(--color-text-muted);
}

/* Menu Section */
.menu {
    padding: 120px 0;
    background: linear-gradient(180deg, var(--color-cream) 0%, var(--color-beige) 100%);
}

.menu-tabs {
    display: flex;
    justify-content: center;
    gap: 16px;
    margin-bottom: 50px;
    flex-wrap: wrap;
}

.tab-btn {
    padding: 12px 28px;
    font-size: 1rem;
    font-weight: 500;
    color: var(--color-text-light);
    background: white;
    border-radius: var(--radius-full);
    box-shadow: var(--shadow-sm);
    transition: var(--transition-base);
}

.tab-btn:hover {
    color: var(--color-primary);
    transform: translateY(-2px);
    box-shadow: var(--shadow-md);
}

.tab-btn.active {
    background: var(--color-primary);
    color: white;
}

.menu-content {
    position: relative;
}

.menu-grid {
    display: none;
    grid-template-columns: repeat(2, 1fr);
    gap: 24px;
    max-width: 900px;
    margin: 0 auto;
}

.menu-grid.active {
    display: grid;
    animation: fadeIn 0.4s ease;
}

@keyframes fadeIn {
    from { opacity: 0; transform: translateY(10px); }
    to { opacity: 1; transform: translateY(0); }
}

.menu-item {
    display: flex;
    justify-content: space-between;
    align-items: flex-start;
    padding: 24px;
    background: white;
    border-radius: var(--radius-lg);
    box-shadow: var(--shadow-sm);
    transition: var(--transition-base);
}

.menu-item:hover {
    box-shadow: var(--shadow-md);
    transform: translateY(-4px);
}

.menu-item-info h3 {
    font-family: var(--font-display);
    font-size: 1.25rem;
    font-weight: 600;
    color: var(--color-text);
    margin-bottom: 6px;
}

.menu-item-info p {
    font-size: 0.9375rem;
    color: var(--color-text-muted);
}

.menu-item-price {
    font-size: 1.25rem;
    font-weight: 600;
    color: var(--color-primary);
    white-space: nowrap;
    margin-left: 16px;
}

/* Features Section */
.features {
    padding: 100px 0;
    background: var(--color-warm-white);
}

.features-grid {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: 40px;
}

.feature-card {
    text-align: center;
    padding: 40px 30px;
    background: white;
    border-radius: var(--radius-xl);
    box-shadow: var(--shadow-sm);
    transition: var(--transition-base);
}

.feature-card:hover {
    box-shadow: var(--shadow-lg);
    transform: translateY(-8px);
}

.feature-icon {
    width: 70px;
    height: 70px;
    margin: 0 auto 24px;
    background: linear-gradient(135deg, var(--color-cream) 0%, var(--color-beige) 100%);
    border-radius: var(--radius-full);
    display: flex;
    align-items: center;
    justify-content: center;
}

.feature-icon svg {
    width: 32px;
    height: 32px;
    color: var(--color-primary);
}

.feature-card h3 {
    font-family: var(--font-display);
    font-size: 1.375rem;
    font-weight: 600;
    margin-bottom: 12px;
    color: var(--color-text);
}

.feature-card p {
    color: var(--color-text-light);
    font-size: 1rem;
}

/* Gallery Section */
.gallery {
    padding: 120px 0;
    background: var(--color-cream);
}

.gallery-grid {
    display: grid;
    grid-template-columns: repeat(4, 1fr);
    grid-template-rows: repeat(2, 280px);
    gap: 20px;
}

.gallery-item {
    border-radius: var(--radius-lg);
    overflow: hidden;
    position: relative;
}

.gallery-item.large {
    grid-row: span 2;
    grid-column: span 2;
}

.gallery-placeholder {
    width: 100%;
    height: 100%;
    background: var(--color-beige);
    display: flex;
    align-items: center;
    justify-content: center;
    transition: var(--transition-base);
}

.gallery-item:hover .gallery-placeholder {
    transform: scale(1.05);
}

.gallery-placeholder svg {
    width: 48px;
    height: 48px;
    color: var(--color-primary);
    opacity: 0.4;
}

/* Contact Section */
.contact {
    padding: 120px 0;
    background: var(--color-warm-white);
}

.contact-grid {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 80px;
}

.contact-info .section-title {
    margin-bottom: 24px;
}

.contact-info > p {
    color: var(--color-text-light);
    margin-bottom: 40px;
    font-size: 1.0625rem;
}

.contact-details {
    display: flex;
    flex-direction: column;
    gap: 24px;
}

.contact-item {
    display: flex;
    gap: 16px;
    align-items: flex-start;
}

.contact-item svg {
    width: 24px;
    height: 24px;
    color: var(--color-primary);
    flex-shrink: 0;
    margin-top: 2px;
}

.contact-item strong {
    display: block;
    font-weight: 600;
    color: var(--color-text);
    margin-bottom: 4px;
}

.contact-item span {
    color: var(--color-text-light);
    font-size: 0.9375rem;
    line-height: 1.6;
}

.contact-form-wrapper {
    background: white;
    padding: 40px;
    border-radius: var(--radius-xl);
    box-shadow: var(--shadow-lg);
}

.form-group {
    margin-bottom: 24px;
}

.form-group label {
    display: block;
    font-weight: 500;
    color: var(--color-text);
    margin-bottom: 8px;
    font-size: 0.9375rem;
}

.form-group input,
.form-group textarea {
    width: 100%;
    padding: 14px 18px;
    border: 2px solid var(--color-border);
    border-radius: var(--radius-md);
    font-family: inherit;
    font-size: 1rem;
    color: var(--color-text);
    transition: var(--transition-base);
    background: var(--color-warm-white);
}

.form-group input:focus,
.form-group textarea:focus {
    outline: none;
    border-color: var(--color-primary);
    background: white;
}

.form-group input::placeholder,
.form-group textarea::placeholder {
    color: var(--color-text-muted);
}

.form-group textarea {
    resize: vertical;
    min-height: 120px;
}

/* Footer */
.footer {
    background: var(--color-text);
    color: var(--color-beige);
    padding: 80px 0 30px;
}

.footer-grid {
    display: grid;
    grid-template-columns: 2fr 1fr 1fr 1.5fr;
    gap: 60px;
    margin-bottom: 60px;
}

.footer-brand .logo {
    color: var(--color-cream);
    margin-bottom: 20px;
}

.footer-brand p {
    color: var(--color-text-muted);
    line-height: 1.7;
    margin-bottom: 24px;
}

.social-links {
    display: flex;
    gap: 16px;
}

.social-links a {
    width: 44px;
    height: 44px;
    background: rgba(255, 255, 255, 0.1);
    border-radius: var(--radius-full);
    display: flex;
    align-items: center;
    justify-content: center;

