}

@keyframes fadeInUp {
    from {
        opacity: 0;
        transform: translateY(30px);
    }
    to {
        opacity: 1;
        transform: translateY(0);
    }
}

.scroll-indicator {
    position: absolute;
    bottom: 40px;
    left: 50%;
    transform: translateX(-50%);
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 10px;
    color: var(--color-text-muted);
    font-size: 0.875rem;
    animation: fadeInUp 0.6s ease 0.5s both;
}

.scroll-arrow {
    width: 24px;
    height: 24px;
    border: 2px solid var(--color-text-muted);
    border-top: none;
    border-left: none;
    transform: rotate(45deg);
    animation: bounce 2s infinite;
}

@keyframes bounce {
    0%, 20%, 50%, 80%, 100% { transform: translateY(0) rotate(45deg); }
    40% { transform: translateY(-10px) rotate(45deg); }
    60% { transform: translateY(-5px) rotate(45deg); }
}

/* Section Styles */
.section-tag {
    display: inline-block;
    font-size: 0.875rem;
    font-weight: 600;
    letter-spacing: 2px;
    text-transform: uppercase;
    color: var(--color-primary);
    margin-bottom: 16px;
}

.section-title {
    font-family: var(--font-display);
    font-size: clamp(2rem, 5vw, 3rem);
    font-weight: 600;
    color: var(--color-text);
    margin-bottom: 16px;
    line-height: 1.2;
}

.section-subtitle {
    font-size: 1.125rem;
    color: var(--color-text-light);
    max-width: 600px;
}

.section-header {
    text-align: center;
    margin-bottom: 60px;
}

.section-header .section-subtitle {
    margin: 0 auto;
}

/* About Section */
.about {
    padding: 120px 0;
    background: var(--color-warm-white);
}

.about-grid {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 80px;
    align-items: center;
}

.about-image-wrapper {
    position: relative;
}

.about-image-wrapper::before {
    content: '';
    position: absolute;
    top: -20px;
    left: -20px;
    right: 20px;
    bottom: 20px;
    border: 3px solid var(--color-primary);
    border-radius: var(--radius-lg);
    z-index: 0;
}

.about-placeholder {
    background: var(--color-beige);
    border-radius: var(--radius-lg);
    aspect-ratio: 4/5;
    display: flex;
    align-items: center;
    justify-content: center;
    position: relative;
    z-index: 1;
}

.about-placeholder svg {
    width: 80px;
    height: 80px;
    color: var(--color-primary);
    opacity: 0.5;
}

.about-content p {
    color: var(--color-text-light);
    margin-bottom: 20px;
    font-size: 1.0625rem;
}

.stats {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: 30px;
    margin-top: 40px;
    padding-top: 40px;
    border-top: 1px solid var(--color-border);
}

.stat-number {
    display: block;
    font-family: var(--font-display);
    font-size: 2.5rem;
    font-weight: 600;
    color: var(--color-primary);
}

.stat-label {
    font-size: 0.9375rem;
    color: var(--color-text-muted);
}

/* Menu Section */
.menu {
    padding: 120px 0;
    background: linear-gradient(180deg, var(--color-cream) 0%, var(--color-beige) 100%);
}

.menu-tabs {
    display: flex;
    justify-content: center;
    gap: 16px;
    margin-bottom: 50px;
    flex-wrap: wrap;
}

.tab-btn {
    padding: 12px 28px;
    font-size: 1rem;
    font-weight: 500;
    color: var(--color-text-light);
    background: white;
    border-radius: var(--radius-full);
    box-shadow: var(--shadow-sm);
    transition: var(--transition-base);
}

.tab-btn:hover {
    color: var(--color-primary);
    transform: translateY(-2px);
    box-shadow: var(--shadow-md);
}

.tab-btn.active {
    background: var(--color-primary);
    color: white;
}

.menu-content {
    position: relative;
}

.menu-grid {
    display: none;
    grid-template-columns: repeat(2, 1fr);
    gap: 24px;
    max-width: 900px;
    margin: 0 auto;
}

