        grid-template-columns: repeat(2, 1fr);
        grid-template-rows: repeat(3, 200px);
    }

    .gallery-item.large {
        grid-row: span 1;
        grid-column: span 2;
    }

    .footer-grid {
        grid-template-columns: 1fr;
        gap: 40px;
    }

    .newsletter-form {
        flex-direction: column;
    }

    .newsletter-form button {
        width: 100%;
    }
}

@media (max-width: 480px) {
    .menu-grid {
        grid-template-columns: 1fr;
    }

    .menu-tabs {
        gap: 10px;
