    }

    .gallery-grid {
        grid-template-columns: 1fr;
        grid-template-rows: repeat(5, 200px);
    }

    .gallery-item.large {
        grid-column: span 1;
    }

    .stats {
        grid-template-columns: 1fr;
        text-align: center;
    }
}

